mapper.select:
SELECT m.member_no, m.member_name, m.member_phone, m.member_birth, m.member_point, m.reservation_count,
/* 마지막 방문 (가장 최근 체크아웃 기준) */ ( SELECT MAX(r.check_out_at) FROM reservations r WHERE r.member_no = m.member_no ) AS lastVisit
FROM members m WHERE m.member_no = #{memberNo}

mapper.update:
UPDATE members
SET member_point = member_point + #{usedPoint}
WHERE member_no = #{memberNo}

UPDATE members
SET member_point = member_point - #{earnedPoint}
WHERE member_no = #{memberNo}

mapper.select:
SELECT IFNULL(SUM(p.total_charge), 0) AS total_amount
FROM members m JOIN reservations r ON m.member_no = r.member_no
LEFT JOIN payments p ON r.member_no = p.idx AND p.pay_status = 'Success'
WHERE m.member_no = #{memberNo}
GROUP BY m.member_no, m.member_name;
